package com.google.gson;

import com.google.gson.stream.JsonReader;
import com.google.gson.stream.MalformedJsonException;
import com.google.gson.internal.Streams;
import com.google.gson.JsonIOException;
import com.google.gson.JsonSyntaxException;
import com.google.gson.JsonParseException;
import com.google.gson.JsonElement;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.function.Executable;
import org.mockito.Mockito;

import java.io.IOException;
import java.io.Reader;
import java.io.StringReader;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

public class JsonParserTest {

  @Test
  public void testParseReader_returnsJsonElementSuccessfully() throws IOException {
    // Arrange
    JsonReader reader = mock(JsonReader.class);
    when(reader.isLenient()).thenReturn(false);
    doNothing().when(reader).setLenient(anyBoolean());

    JsonElement expectedElement = mock(JsonElement.class);

    // Mock Streams.parse to return expectedElement
    try (var mockedStatic = Mockito.mockStatic(Streams.class)) {
      mockedStatic.when(() -> Streams.parse(reader)).thenReturn(expectedElement);

      // Act
      JsonElement result = JsonParser.parseReader(reader);

      // Assert
      assertSame(expectedElement, result);
      verify(reader).isLenient();
      verify(reader).setLenient(true);
      verify(reader).setLenient(false);
    }
  }

  @Test
  public void testParseReader_throwsJsonParseExceptionOnStackOverflowError() throws IOException {
    // Arrange
    JsonReader reader = mock(JsonReader.class);
    when(reader.isLenient()).thenReturn(true);
    doNothing().when(reader).setLenient(anyBoolean());

    StackOverflowError error = new StackOverflowError("stack overflow");

    try (var mockedStatic = Mockito.mockStatic(Streams.class)) {
      mockedStatic.when(() -> Streams.parse(reader)).thenThrow(error);

      // Act
      JsonParseException thrown = assertThrows(JsonParseException.class, () -> JsonParser.parseReader(reader));

      // Assert
      assertTrue(thrown.getMessage().contains("Failed parsing JSON source"));
      assertSame(error, thrown.getCause());
      verify(reader).setLenient(true);
      verify(reader).setLenient(true);
    }
  }

  @Test
  public void testParseReader_throwsJsonParseExceptionOnOutOfMemoryError() throws IOException {
    // Arrange
    JsonReader reader = mock(JsonReader.class);
    when(reader.isLenient()).thenReturn(false);
    doNothing().when(reader).setLenient(anyBoolean());

    OutOfMemoryError error = new OutOfMemoryError("out of memory");

    try (var mockedStatic = Mockito.mockStatic(Streams.class)) {
      mockedStatic.when(() -> Streams.parse(reader)).thenThrow(error);

      // Act
      JsonParseException thrown = assertThrows(JsonParseException.class, () -> JsonParser.parseReader(reader));

      // Assert
      assertTrue(thrown.getMessage().contains("Failed parsing JSON source"));
      assertSame(error, thrown.getCause());
      verify(reader).setLenient(true);
      verify(reader).setLenient(false);
    }
  }

  @Test
  public void testParseReader_resetsLenientFlagEvenIfExceptionThrown() throws IOException {
    // Arrange
    JsonReader reader = mock(JsonReader.class);
    when(reader.isLenient()).thenReturn(false);
    doNothing().when(reader).setLenient(anyBoolean());

    RuntimeException runtimeException = new RuntimeException("runtime exception");

    try (var mockedStatic = Mockito.mockStatic(Streams.class)) {
      mockedStatic.when(() -> Streams.parse(reader)).thenThrow(runtimeException);

      // Act & Assert
      RuntimeException thrown = assertThrows(RuntimeException.class, () -> JsonParser.parseReader(reader));
      assertSame(runtimeException, thrown);
      verify(reader).setLenient(true);
      verify(reader).setLenient(false);
    }
  }
}
